	private function addWordChain($noun,$facet=[],$synonyms=[],$adj=[],$verbAct=[],$verbTo=[],$adverbs=[],$assoc=[],$positions=[],$express=[]){
		$wordNoun=0;
		$word=$this->findNoun($noun);
		$syno=$this->findNoun($synonyms);
		$asso=$this->findNoun($assoc);
		if (!$word){
			error_log('Noun Not Found: '.$noun);
			if ($syno){$word=$syno;}else{
				if ($asso){$word=$asso;}
			}
			$wordNoun=array_keys($word);
		}
		if (is_array($facet)){
			//converts facet names to indexes...
			foreach ($facet as $f=>$acet){
				if (is_string($acet)){
					$facet[$f]=T13Facets::getFacetIndex($acet);
				}
			}
		}
		$nuword=['Nouns'=>$synonyms,'Facet'=>$facet,'Adjectives'=>$adj,'VerbActor'=>$verbAct,'VerbTarget'=>$verbTo,'Adverbs'=>$adverbs,'Associated'=>$assoc,'Positions'=>$position,'Expressions'=>$express];
		if (!$wordNoun&&!isset($this->words[$noun])){
			$this->words[$noun]=$nuword;
			return true;
		}else{
			$this->words[$wordNoun]=T13Conflicts::array_merge_recursive_distinct($this->words[$wordNoun],$nuword);
			return true;
		}
	}
