	public function findNoun($noun){
		if (is_string($noun)){
			foreach($this->words as $n=>$values){
				if (T13Types::contains($n,$noun)){
					return array($n=>$values);
				}else{
					if (T13Types::contains(json_encode($values),$noun)){
						return array($n=>$values);
					}
				}
			}
		}elseif(is_array($noun)){
			foreach($noun as $i=>$n){
				$wor=$this->findNoun($n);
				if ($wor){
					return $wor;
				}
			}
		}
		error_log('findNoun ('.$noun.') failed!');
		return false;
	}
	public function findFacet($facet){
		if (is_string($facet)){
			foreach($this->words as $n=>$values){
				if (T13Types::contains($values['Facet'],$facet)){
					return array($n=>$values);
				}else{
					if (T13Types::contains(json_encode($values),$facet)){
						return array($n=>$values);
					}
				}
			}
		}elseif(is_array($facet)){
			foreach($facet as $i=>$f){
				$wor[]=$this->findFacet($f);

			}
			return $wor;
		}
		error_log('findNoun ('.$noun.') failed!');
		return false;
	}
