	public function extractMutants($string){
		$list=explode(',',$string);
		foreach($list as $i=>$word){
			$permute=preg_split('/([\(\)])+/', $word);
			foreach($permute as $j=>$wyrd){
				if (T13Types::contains($wyrd,'/')){
					$permutations=preg_split('/([\/])+/', $wyrd);
					$ret[]=array($permute[$j-1],$permutations,$permute[$j+1]);
				}
			}

		}
		return $ret;
	}
	public function drillDown($array){
		if (is_array($array)){
			return $this->drillDown($array[array_rand($array)]);

		}else{
			if (T13Types::contains($array,',')){
				return $this->drillDown(array_rand(array_flip(explode(',', $array))));
			}else{
				return $array;
			}
		}

	}
