				return $words;
			}
		}elseif (is_array($words)){
			$wyrd=$words;
		}
		if (is_numeric($preference)){
			$wyrd=$wyrd[$preference];
		}elseif (in_array($preference, $wyrd)){
			$wyrd=$preference;
		}else{
			$wyrd = $wyrd[array_rand($wyrd)];
		}
		return $wyrd;
	}
	public function conjugateRule($rule='$subject (////[All]//) $verb[4]',$tense=['Past','Simple'],$person='1s'){
		$ret='';
		if (T13Types::contains($rule,'(')){
			//permutate the required (/////) sections
			$rule=preg_split('/([\(\)])+/', $rule);
			foreach($rule as $i=>$word){
				//actually these are chunks of texts not words
				if (T13Types::contains($word,'/')){
					//permute for person
					$word=preg_split('/([\/])+/', $word);
					$nuword=$word[self::$grammar['Person'][$person]['Index']];
					$ret.=$nuword;
				}else{$ret.=$word;}
			}
		}
		if(T13Types::contains($ret,'{')){
			//optional text in []
			$nuword=preg_split('/([\{\}])+/', $ret);
			$ret="";
			foreach($nuword as $j=>$wyrd){
				$wyrd=$this->selectWordFromString($wyrd);
				if ($j%2){
					if (T13Dice::RNG(1,10)==1){
						$ret.=$wyrd;
					}
				}else{
					$ret.=$wyrd;
				}

			}
		}
		return $ret;
	}
	public function buildSentence($sentence='$conjugatedVerbActor $object',$tense=['Present','Simple'],$person='1s',$data){
		$subject='Someone';
		$actorDeterminer='Someone\'s';
		$object='Something';
		$actorVerb='Watch';
		if (isset($data['Actor']['Gender']['Preference'])){$preference=$data['Actor']['Gender']['Preference'];}else{$preference='random';}
		if (isset(self::$grammar['Person'][$person])){
			$actor=self::$grammar['Person'][$person];
		}elseif(isset(self::$grammar['Person']['3s'][$person])){
			$actor=self::$grammar['Person']['3s'][$person];
		}
		$subject=$this->selectWordFromString($actor['Subject'],$preference);
		$actorDeterminer=$this->selectWordFromString($actor['Determiner'],$preference);
		$actorVerb=$this->selectedWordFromString($data['Actor']['VerbActor']);
		$actorAdjective=$this->selectedWordFromString($data['Actor']['Adjectives']);
		$actorAdverb=$this->selectedWordFromString($data['Actor']['Adverbs']);
		$actorObject=$this->selectedWordFromString($data['Actor']['Object']['Nouns']);
		$actorObjectAdjective=$this->selectedWordFromString($data['Actor']['Object']['Adjectives']);
		$actorObjectVerb=$this->selectedWordFromString($data['Actor']['Object']['Verbs']);
		$actorObjectAdverb=$this->selectedWordFromString($data['Actor']['Object']['Adverbs']);
		$verb=array_rand(array_flip(array($actorVerb,$actorObjectVerb)));
		$conjugatedVerbActor=$this->conjugateVerb($verb,$tense,$person);
		if (isset($data['Target'])){
			if (isset($data['Target']['PersonPreference'])){$preference=$data['Target']['PersonPreference'];}else{$preference='random';}
			if (isset($data['Target']['Person'])){
				if (isset(self::$grammar['Person'][$data['Target']['Person']])){
					$target=self::$grammar['Person'][$data['Target']['Person']];
				}else if(isset(self::$grammar['Person']['3s'][$data['Target']['Person']])){
					$target=self::$grammar['Person']['3s'][$data['Target']['Person']];
				}
				$object=$this->selectWordFromString($target['Subject'],$preference);
				$objectDeterminer  =$this->selectWordFromString($target['Determiner'],$preference);
				$objectVerb=$this->selectedWordFromString($data['Target']['VerbTarget']);
				$objectAdjective=$this->selectedWordFromString($data['Target']['Adjectives']);
				$objectAdverb=$this->selectedWordFromString($data['Target']['Adverbs']);
				$objectObject=$this->selectedWordFromString($data['Target']['Object']['Nouns']);
				$objectObjectAdjective=$this->selectedWordFromString($data['Target']['Object']['Adjectives']);
				$objectObjectVerb=$this->selectedWordFromString($data['Target']['Object']['Verbs']);
				$objectObjectAdverb=$this->selectedWordFromString($data['Target']['Object']['Adverbs']);
				$verb=array_rand(array_flip(array($objectVerb,$objectObjectVerb)));
				$conjugatedVerbObject=$this->conjugateVerb($verb,$tense,$person);
			}

		}
		return new DoubleQuote($sentence);

	}
	public function permuteVerb($array){
		//'B(uy/uys/uying/ought)'
		if (is_string($array)){$array=$this->extractMutants($array);}
		$verb=array();
		if (isset($array[0])&&is_array($array[0])){
			$array=$array[array_rand($array)];
		}
		if (isset($array[1])){
			foreach($array[1] as $i=>$mutant){
				$verb[]=$array[0].$mutant.$array[2];
			}
		}else{error_log('Permuted Verb is unexpectedly not an Array');}
		if (!isset($verb[4])&&isset($verb[3])){
			$verb[4]=$verb[3];
		}
		return $verb;
	}

	public function conjugateVerb($array,$tense=['Past','Simple'],$person='1s'){
		if (isset(self::$grammar['Person'][$person])){
			$person=self::$grammar['Person'][$person];
		}elseif(isset(self::$grammar['Person']['3s'][$person])){
			$person=self::$grammar['Person']['3s'][$person];
		}
		$subject=$person['Subject'];
		$verb=$this->permuteVerb($array);
		$rule=self::$grammar['Tenses'][$tense[0]][$tense[1]]['Rule'];
		$out=new DoubleQuote($rule);
		return $out;
	}
	public function writeWord($noun,$mode,$plural,$tense=['Past','Simple'],$person='1s'){
		$word=$this->findNoun($noun);
		switch($mode){
			case 'Noun':
				$outnoun=explode(',',array_keys($word));
			break;
			case 'Synonym':
				$outnoun=array_merge(explode(',', $noun),$word['Synonyms']);
			break;
			case 'Adjective':
				$output=$word['Adjectives'];
			break;
			case 'VerbActor':
				$output=$word['VerbActor'];
			break;
			case 'VerbTarget':
				$output=$word['VerbTarget'];
			break;
			case 'Adverb':
				$output=$word['Adverbs'];
			break;
			case 'Positions':
				$output=$word['Positions'];
			break;
			case 'Expressions':
				$output=$word['Expressions'];
			break;
			case 'Associated':
				$outnoun=array_merge(explode(',', $noun),$word['Associated']);
			break;
			default:
			error_log('Mode Not found '.$mode);
			break;
		}
		if (isset($outnoun)){
			$out=$this->extractMutants($this->drillDown($outnoun));
			$ret=$out[0].($plural)?$out[2]:$out[1];
		}
		if (isset($output)){
			$ret=$this->conjugateVerbs($this->drillDown($output),$tense,$person);
		}
		return $ret;
	}

}


